            aCross = RotL64(pSnow[((S_BLOCK1 - aIndex + 1654U)) & S_BLOCK1], 29U) ^ RotL64(aSource[((S_BLOCK1 - aIndex + 2848U)) & S_BLOCK1], 54U);
