            //
            aOrbiterI = (aWandererA + RotL64(aPrevious, 50U)) + 2410027096777063664U;
            aOrbiterJ = (aWandererI + RotL64(aScatter, 41U)) + 3587712631178438953U;
            aOrbiterG = ((aWandererH + RotL64(aIngress, 29U)) + RotL64(aCarry, 5U)) + 8918435264575782594U;
            aOrbiterA = ((aWandererK + RotL64(aCross, 39U)) + 11447411010132663526U) + aNonceWordH;
