            //
            aOrbiterA = ((aOrbiterA + aOrbiterH) + 6805444174790109373U) + aOrbiterUpdateSaltC[(((31U - aIndex) + 14U)) & S_SALT1];
            aOrbiterK = (aOrbiterK ^ aOrbiterA) ^ 11015687409210250067U;
            aOrbiterK = RotL64((aOrbiterK * 3277882442747436323U), 37U);
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterK) + 15314522254017970812U;
            aOrbiterB = ((aOrbiterB ^ aOrbiterJ) ^ 10057690566838331842U) ^ aOrbiterUpdateSaltE[(((31U - aIndex) + 11U)) & S_SALT1];
            aOrbiterB = RotL64((aOrbiterB * 4439749699637478477U), 35U);
            //
            aOrbiterB = (aOrbiterB + aOrbiterD) + 5223994418509883233U;
            aOrbiterA = (aOrbiterA ^ aOrbiterB) ^ 13666139904629656757U;
            aOrbiterA = RotL64((aOrbiterA * 5019457446330703667U), 39U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterE) + 2499715212736845765U;
            aOrbiterI = (aOrbiterI ^ aOrbiterC) ^ 7861255108889457509U;
            aOrbiterI = RotL64((aOrbiterI * 14519418358027585635U), 23U);
            //
            aOrbiterE = ((aOrbiterE + aOrbiterA) + 16172860561317593376U) + aOrbiterUpdateSaltB[(((31U - aIndex) + 8U)) & S_SALT1];
            aOrbiterJ = (aOrbiterJ ^ aOrbiterE) ^ 7457299354202447058U;
            aOrbiterJ = RotL64((aOrbiterJ * 7920414556253704809U), 3U);
            //
            aOrbiterH = ((aOrbiterH + aOrbiterI) + 4296482029475991877U) + aNonceWordC;
            aOrbiterF = ((aOrbiterF ^ aOrbiterH) ^ 12383893988600917436U) ^ aOrbiterUpdateSaltD[((aIndex + 12U)) & S_SALT1];
            aOrbiterF = RotL64((aOrbiterF * 1349517954264440157U), 47U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterB) + 11181741373232009147U;
            aOrbiterE = (aOrbiterE ^ aOrbiterG) ^ 9896947853160815172U;
            aOrbiterE = RotL64((aOrbiterE * 6594947075413056859U), 27U);
            //
            aOrbiterD = (aOrbiterD + aOrbiterC) + 4019967110110881073U;
            aOrbiterH = ((aOrbiterH ^ aOrbiterD) ^ 6260371794413976647U) ^ aNonceWordA;
            aOrbiterH = RotL64((aOrbiterH * 620676041360102209U), 51U);
            //
            aOrbiterK = (aOrbiterK + aOrbiterF) + 557621887220453679U;
            aOrbiterD = (aOrbiterD ^ aOrbiterK) ^ 11940098560081764132U;
            aOrbiterD = RotL64((aOrbiterD * 1142253333044255405U), 13U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterG) + 6932693203933693610U;
            aOrbiterC = ((aOrbiterC ^ aOrbiterF) ^ 4533545166978020835U) ^ aNonceWordN;
            aOrbiterC = RotL64((aOrbiterC * 1856784702200801827U), 29U);
            //
            aIngress = aOrbiterI ^ RotL64(aOrbiterH, 12U);
            aIngress = aIngress + (aOrbiterE ^ RotL64(aOrbiterF, 27U));
            aIngress = aIngress + (RotL64(aOrbiterB, 53U) ^ aOrbiterK);
            aIngress = aIngress + (RotL64(aOrbiterA, 51U) ^ aOrbiterJ);
            aIngress = aIngress + (RotL64(aOrbiterC, 19U) ^ aOrbiterD);
            aIngress = aIngress + RotL64(aOrbiterG, 57U);
            aIngress = TwistMix64::DiffuseC((aIngress + aScatter));
            //
            aWandererJ = aWandererJ + (((RotL64(aScatter, 13U) + RotL64(aOrbiterD, 53U)) + aOrbiterI) + RotL64(aCarry, 57U));
            aWandererE = aWandererE ^ ((RotL64(aIngress, 29U) + RotL64(aOrbiterE, 58U)) + aOrbiterH);
            aWandererC = aWandererC + (((RotL64(aCross, 47U) + aOrbiterJ) + RotL64(aOrbiterB, 39U)) + aWandererUpdateSaltB[(((31U - aIndex) + 21U)) & S_SALT1]);
            aWandererD = aWandererD ^ (((RotL64(aPrevious, 24U) + RotL64(aOrbiterI, 5U)) + aOrbiterG) + aNonceWordE);
